const body = $input.first().json.body || $input.first().json;
const firstName = body.first_name || body.name?.split(' ')[0] || 'there';
const phone = body.phone || body.phone_number || '';
const score = body.ai_score || '';
const recommendation = body.ai_recommendation || 'Follow up immediately';
let cleanPhone = phone.replace(/[\s\-\(\)]/g, '');
if (cleanPhone.startsWith('00')) { cleanPhone = '+' + cleanPhone.slice(2); }
else if (cleanPhone.startsWith('0') && !cleanPhone.startsWith('+')) { cleanPhone = '+49' + cleanPhone.slice(1); }
else if (!cleanPhone.startsWith('+')) { cleanPhone = '+' + cleanPhone; }
if (!cleanPhone || cleanPhone.length < 8) throw new Error('Invalid phone number: ' + phone);
return [{ json: { firstName, phone: cleanPhone, score, recommendation, contactId: body.id || body.contact_id || '' } }];

